		templ_7745c5c3_Err = templruntime.WriteString(templ_7745c5c3_Buffer, 94, "\"><div><label class=\"block text-body font-medium text-text\">Reason *</label> <input type=\"text\" name=\"void_reason\" x-model=\"voidReason\" maxlength=\"500\" placeholder=\"Enter reason for voiding...\" class=\"mt-2 block w-full rounded-md border border-border-input px-3 py-2 text-body outline-none focus:ring-2 focus:ring-primary-focus\"><p x-show=\"voidSubmitted && !voidReason.trim()\" class=\"mt-1 text-small text-danger\">Reason is required.</p></div><div class=\"mt-6 flex items-center justify-end gap-3\"><button type=\"button\" @click=\"showVoidModal = false\" class=\"rounded-md border border-border px-4 py-2 text-body font-semibold text-text hover:bg-background\">Cancel</button> <button type=\"submit\" @click=\"voidSubmitted = true; if (!voidReason.trim()) $event.preventDefault()\" class=\"rounded-md bg-danger px-4 py-2 text-body font-semibold text-white hover:bg-danger-hover\">Void Reconciliation</button></div></form></div></div></div><script>\n\t\tfunction reconcilePage() {\n\t\t\treturn {\n\t\t\t\theader: { account_id: \"\", statement_date: \"\", ending_balance: \"\" },\n\t\t\t\tendingBalance: 0,\n\t\t\t\tbeginningBalance: 0,\n\t\t\t\tcandidates: [],  // [{id: string, amount: number}]\n\t\t\t\tselected: [],    // string IDs of checked lines\n\n\t\t\t\tshowVoidModal: false,\n\t\t\t\tvoidRecID: 0,\n\t\t\t\tvoidDate: \"\",\n\t\t\t\tvoidReason: \"\",\n\t\t\t\tvoidSubmitted: false,\n\n\t\t\t\tinit() {\n\t\t\t\t\tconst url = new URL(window.location.href);\n\t\t\t\t\tthis.header.account_id     = url.searchParams.get(\"account_id\")     || \"\";\n\t\t\t\t\tthis.header.statement_date = url.searchParams.get(\"statement_date\") || \"\";\n\t\t\t\t\tthis.header.ending_balance = url.searchParams.get(\"ending_balance\") || \"\";\n\n\t\t\t\t\tconst eb = parseFloat(url.searchParams.get(\"ending_balance\") || \"0\");\n\t\t\t\t\tthis.endingBalance = isNaN(eb) ? 0 : eb;\n\n\t\t\t\t\tconst bb = parseFloat(this.$el.dataset.beginning || \"0\");\n\t\t\t\t\tthis.beginningBalance = isNaN(bb) ? 0 : bb;\n\n\t\t\t\t\ttry {\n\t\t\t\t\t\tconst raw = JSON.parse(this.$el.dataset.candidates || \"[]\");\n\t\t\t\t\t\tthis.candidates = raw.map(c => ({ id: String(c.id), amount: parseFloat(c.amount) || 0 }));\n\t\t\t\t\t} catch (_) { this.candidates = []; }\n\n\t\t\t\t\t// Pre-select lines from accepted suggestions.\n\t\t\t\t\ttry {\n\t\t\t\t\t\tconst accepted = JSON.parse(this.$el.dataset.acceptedLines || \"[]\");\n\t\t\t\t\t\tfor (const id of accepted) {\n\t\t\t\t\t\t\tconst sid = String(id);\n\t\t\t\t\t\t\tif (!this.selected.includes(sid)) {\n\t\t\t\t\t\t\t\tthis.selected.push(sid);\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t}\n\t\t\t\t\t} catch (_) {}\n\t\t\t\t},\n\n\t\t\t\tselectedNet() {\n\t\t\t\t\treturn this.selected.reduce((sum, id) => {\n\t\t\t\t\t\tconst c = this.candidates.find(c => c.id === id);\n\t\t\t\t\t\treturn c ? sum + c.amount : sum;\n\t\t\t\t\t}, 0);\n\t\t\t\t},\n\n\t\t\t\tclearedBalance() { return this.beginningBalance + this.selectedNet(); },\n\t\t\t\tdifference()     { return this.endingBalance - this.clearedBalance(); },\n\t\t\t\tdiffOk()         { return Math.abs(this.difference()) < 0.005; },\n\n\t\t\t\tfmt(n) {\n\t\t\t\t\tconst v = typeof n === \"number\" ? n : parseFloat(n) || 0;\n\t\t\t\t\treturn v.toFixed(2);\n\t\t\t\t},\n\n\t\t\t\ttoggleAll(e) {\n\t\t\t\t\tif (e.target.checked) {\n\t\t\t\t\t\tthis.selected = this.candidates.map(c => c.id);\n\t\t\t\t\t} else {\n\t\t\t\t\t\tthis.selected = [];\n\t\t\t\t\t}\n\t\t\t\t},\n\n\t\t\t\topenVoidModal(recID, date) {\n\t\t\t\t\tthis.voidRecID = recID;\n\t\t\t\t\tthis.voidDate  = date;\n\t\t\t\t\tthis.voidReason = \"\";\n\t\t\t\t\tthis.voidSubmitted = false;\n\t\t\t\t\tthis.showVoidModal = true;\n\t\t\t\t},\n\n\t\t\t\tbeforeSubmit(e) {\n\t\t\t\t\tif (!this.diffOk()) e.preventDefault();\n\t\t\t\t},\n\t\t\t};\n\t\t}\n\t</script>")
